import React, { useRef } from 'react';
import { Button, Container, Typography } from '@mui/material';
import { PDFDocument } from 'pdf-lib';
import { saveAs } from 'file-saver';
import html2canvas from 'html2canvas';

const PdfWithImageFromExisting = () => {
    const contentRef = useRef();

    const generatePDF = async () => {
        try {
            // Asegúrate de que el archivo PDF esté en la carpeta public
            const existingPdfBytes = await fetch('./AAF010 Evaluación Económica.pdf').then((res) => {
                if (!res.ok) throw new Error("No se pudo cargar el archivo PDF");
                return res.arrayBuffer();
            });

            // Cargar el PDF
            const pdfDoc = await PDFDocument.load(existingPdfBytes);

            // Capturar el contenido como imagen con alta resolución
            const canvas = await html2canvas(contentRef.current, {
                scale: 4, // Escala de la imagen (aumenta la resolución)
            });

            const imgData = canvas.toDataURL('image/png');

            // Obtener el tamaño del contenido para pegar la imagen en el PDF con las mismas proporciones
            const width = contentRef.current.offsetWidth;
            const height = contentRef.current.offsetHeight;

            // Convertir la imagen a un formato compatible con pdf-lib
            const img = await pdfDoc.embedPng(imgData);

            // Crear una página nueva y pegar la imagen en ella
            const page = pdfDoc.addPage([width, height]);
            const { width: imgWidth, height: imgHeight } = img.size();

            // Pegar la imagen en el PDF (ajustar posición y tamaño según sea necesario)
            page.drawImage(img, {
                x: 0,
                y: 0,
                width: imgWidth,
                height: imgHeight,
            });

            // Guardar el archivo PDF modificado
            const pdfBytes = await pdfDoc.save();
            const modifiedPdfBlob = new Blob([pdfBytes], { type: 'application/pdf' });

            // Descargar el archivo PDF modificado
            saveAs(modifiedPdfBlob, './Informes/Comun/AAF010 Evaluación Económicaff.pdf');
        } catch (error) {
            console.error("Error al cargar o procesar el archivo PDF:", error);
        }
    };

    return (
        <Container>
            <div ref={contentRef} style={{ width: '100%', height: '200px', backgroundColor: '#f3f3f3', padding: '20px' }}>
                <Typography variant="h4">Este es el contenido que se convertirá en una imagen</Typography>
                <Typography variant="body1">Puede ser cualquier componente de React, como un formulario, una tabla, etc.</Typography>
            </div>

            <Button onClick={generatePDF} variant="contained" color="primary" style={{ marginTop: '20px' }}>
                Generar PDF Modificado
            </Button>
        </Container>
    );
};

export default PdfWithImageFromExisting;
